using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");

// Load and transform training data
var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to boolean Label column
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
        (input, output) => output.Label = string.Equals(input.ChurnedRaw, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: "ChurnLabelMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(rawData);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// Evaluate and log metrics
var predictions = model.Transform(rawData);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — Accuracy: {metrics.Accuracy:P2}, AUC: {metrics.AreaUnderRocCurve:P2}, F1: {metrics.F1Score:P2}");

app.MapGet("/", () => "ChurnPredictor API is running. POST /predict with customer data.");

app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = Math.Round(prediction.Probability, 4),
        prediction.Score
    });
});

app.MapGet("/metrics", () => new
{
    metrics.Accuracy,
    metrics.AreaUnderRocCurve,
    metrics.F1Score,
    metrics.PositivePrecision,
    metrics.PositiveRecall
});

app.Run();

// Helper type for custom label mapping
public class LabelMapping
{
    public bool Label { get; set; }
}

